const MAGNIX_LLM_DEFAULTS = {"classify":"deepseek","editorial_brief":"deepseek","outreach":"deepseek","video_draft":"deepseek","carousel_draft":"deepseek","content_draft":"anthropic","content_draft_general":"deepseek","content_qa":"anthropic","housex_article":"anthropic"};

function hasLlmKey(raw) {
  return String(raw || '').trim().length > 12;
}

function envProvider(taskId) {
  const key = `MAGNIX_LLM_${String(taskId || '')
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, '_')}_PROVIDER`;
  const v = String($env[key] || '').trim().toLowerCase();
  if (v === 'deepseek' || v === 'anthropic') return v;
  return null;
}

function resolveProvider(taskId) {
  return envProvider(taskId) || MAGNIX_LLM_DEFAULTS[taskId] || 'deepseek';
}

function hasProvider(provider) {
  if (provider === 'anthropic') return hasLlmKey($env.ANTHROPIC_API_KEY);
  return hasLlmKey($env.DEEPSEEK_API_KEY);
}

function anthropicModelForTask(taskId) {
  if (taskId === 'classify') {
    return $env.ANTHROPIC_CLASSIFY_MODEL || 'claude-haiku-4-5-20251001';
  }
  if (taskId === 'video_draft') {
    return $env.ANTHROPIC_VIDEO_MODEL || $env.ANTHROPIC_DRAFT_MODEL || 'claude-sonnet-4-6';
  }
  return $env.ANTHROPIC_DRAFT_MODEL || $env.ANTHROPIC_MODEL || 'claude-sonnet-4-6';
}

async function callDeepSeekLlm(ctx, opts) {
  const {
    system,
    userPayload,
    temperature = 0.35,
    maxTokens = 4096,
    jsonMode = true,
  } = opts;
  return ctx.helpers.httpRequest({
    method: 'POST',
    url: $env.DEEPSEEK_API_URL || 'https://api.deepseek.com/chat/completions',
    headers: {
      Authorization: `Bearer ${$env.DEEPSEEK_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: {
      model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
      temperature,
      max_tokens: maxTokens,
      ...(jsonMode ? { response_format: { type: 'json_object' } } : {}),
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: userPayload },
      ],
    },
    json: true,
  });
}

async function callAnthropicLlm(ctx, opts) {
  const {
    system,
    userPayload,
    temperature = 0.35,
    maxTokens = 4096,
    taskId = 'content_draft',
  } = opts;
  return ctx.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'Content-Type': 'application/json',
    },
    body: {
      model: anthropicModelForTask(taskId),
      max_tokens: maxTokens,
      temperature,
      system,
      messages: [{ role: 'user', content: userPayload }],
    },
    json: true,
  });
}

async function invokeMagnixLlm(ctx, taskId, opts) {
  const primary = resolveProvider(taskId);
  const fallback = primary === 'deepseek' ? 'anthropic' : 'deepseek';
  const errors = [];

  for (const provider of [primary, fallback]) {
    if (!hasProvider(provider)) continue;
    try {
      if (provider === 'deepseek') {
        return await callDeepSeekLlm(ctx, opts);
      }
      return await callAnthropicLlm(ctx, { ...opts, taskId });
    } catch (e) {
      errors.push(`${provider}: ${e.message}`);
    }
  }

  if (!hasProvider('deepseek') && !hasProvider('anthropic')) {
    throw new Error('Thiếu DEEPSEEK_API_KEY hoặc ANTHROPIC_API_KEY trên n8n env');
  }
  throw new Error(errors.join(' | ') || 'LLM providers failed');
}

const intake = $input.first().json;
if (!intake.ok) return [{ json: intake }];

const system = `Bạn là biên tập PR BĐS HouseX — Value-First, buyer-first, **không hard sell**.

## Phong cách (bắt buộc)

- Viết như VnExpress / CafeLand / Tuổi Trẻ: câu văn trôi chảy, có số liệu trích nguồn.
- **Cấm** markdown bold \`**...**\` — nhấn mạnh bằng cách diễn đạt, không dùng ký hiệu.
- **Cấm** heading/meta dạng prompt: «Liên hệ với…», «Góc nhìn thực tế:», «Gợi ý tra cứu», «Hành động tiếp theo trên HouseX», «Bước tiếp theo…», «Kết luận góc nhìn HouseX», «→ [link]».
- **Cấm** bullet CTA kiểu checklist cuối bài — kết bài bằng 1–2 đoạn văn tự nhiên.
- H2/H3 là **câu hỏi hoặc nhận định** (Q&A SEO), không phải chỉ dẫn cho người viết.
- Link nội bộ HouseX: \`[nhãn](/du-an/slug)\` hoặc \`/tin-tuc/slug\` — không URL tuyệt đối housex.vn trong body.
- Link ngoài: markdown \`[Tên báo](https://...)\` — ưu tiên nguồn user cung cấp trong \`source_refs\`.
- Quy hoạch / ga / metro chưa vận hành: ghi rõ «(quy hoạch)», «tham khảo bản đồ», «theo thông tin CĐT» — không cam kết thời gian cố định mọi khung giờ.
- Khoảng cách km chỉ khi intake ghi \`distance_km_ok: true\`; ưu tiên **phút di chuyển theo CĐT** khi có.
- Không cam kết duyệt vay, không hứa chắc chắn tăng giá, không lãi suất % tự bịa (chỉ trích văn bản/NHNN/CĐT).

## Legal Gate

Chỉ dùng \`facts[]\` trong \`legal_retrieval_pack\` khi có. \`source_refs\` output = claim_id hoặc URL báo chí.

## Kết bài DTA (khi \`project_slug\` = dta-happy-home-nhon-trach)

Chọn **một** hướng kết (theo \`closing_variant\` trong intake) và **viết lại bằng lời mình**, không copy nguyên mẫu:

| closing_variant | Ý chính cần lồng ghép |
|-----------------|------------------------|
| \`quyHoachVen\` | Vùng ven Nhơn Trạch/Long Thành + hành lang giao thông; DTA City; ga quy hoạch ~5 km; TOD; gia đình trẻ |
| \`todAnCu\` | TOD thực tế cho lao động; ga quy hoạch; giá CĐT từ 448 triệu; Block A10 |
| \`todNoiThanhVsVen\` | TOD nội thành vs vùng ven; DTA 448–700 triệu; hạ tầng cầu/cao tốc |
| \`gaQuyHoach\` | Phước An–Phú Hội; ga S12/S13 quy hoạch; ~5 km; Long Thành ~20 phút (CĐT); TOD kiểu mẫu |
| \`nhonTrachTod\` | Tam giác hạ tầng 10 phút cao tốc / 20 phút sân bay / 5 km ga quy hoạch |

## Cấu trúc body (markdown)

- 3–5 section \`##\` — mỗi section 2–4 đoạn.
- Có thể dùng danh sách \`-\` cho số liệu (tối đa 1 list/section).
- Kết: disclaimer nghiêng một dòng \`*HouseX tổng hợp…*\` (không phải công bố NN nếu tổng hợp báo chí).`;

