function extractJsonString(raw) {
  if (raw == null) throw new Error('EMPTY_LLM_OUTPUT');
  const s = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  return (fenced ? fenced[1] : s).trim();
}

const item = $input.first().json;
if (item.error) {
  return [{ json: { ok: false, parse_error: item.llm_error || 'LLM_ERROR', request_id: item.request_id } }];
}

const raw =
  item.llm_raw?.content?.[0]?.text ??
  item.llm_raw?.choices?.[0]?.message?.content ??
  item.llm_raw;

try {
  const parsed = JSON.parse(extractJsonString(raw));
  const required = ['slug', 'title', 'excerpt', 'body'];
  for (const k of required) {
    if (!parsed[k] || !String(parsed[k]).trim()) throw new Error(`MISSING_${k.toUpperCase()}`);
  }
  if (!Array.isArray(parsed.tags)) parsed.tags = [];
  if (!Array.isArray(parsed.project_slugs)) {
    parsed.project_slugs = item.project_slug ? [item.project_slug] : [];
  }
  if (!Array.isArray(parsed.source_refs)) parsed.source_refs = item.source_refs || [];

  return [{
    json: {
      ok: true,
      request_id: item.request_id,
      topic: item.topic,
      segment: item.segment,
      project_slug: item.project_slug,
      run_devil: item.run_devil,
      article: {
        slug: String(parsed.slug).slice(0, 120),
        title: String(parsed.title).slice(0, 500),
        excerpt: String(parsed.excerpt).slice(0, 500),
        body: String(parsed.body).slice(0, 60000),
        seo_title: parsed.seo_title ? String(parsed.seo_title).slice(0, 500) : null,
        seo_desc: parsed.seo_desc ? String(parsed.seo_desc).slice(0, 500) : null,
        tags: parsed.tags.slice(0, 8),
        project_slugs: parsed.project_slugs.slice(0, 5),
        source_refs: parsed.source_refs.slice(0, 12),
      },
      llm_provider: item.llm_provider,
    },
  }];
} catch (e) {
  return [{
    json: {
      ok: false,
      request_id: item.request_id,
      parse_error: e.message,
      raw_preview: String(raw).slice(0, 300),
    },
  }];
}

const BANNED_PHRASES = ["Liên hệ với","Góc nhìn thực tế:","Góc nhìn người mua nhà:","Gợi ý tra cứu","Hành động tiếp theo trên HouseX","Bước tiếp theo trên HouseX","Kết luận góc nhìn HouseX","buyer-first"];

const FORBIDDEN = [
  /cam kết.*duyệt/i,
  /đảm bảo.*(vay|duyệt)/i,
  /100%\s*(thành công|duyệt)/i,
  /chắc chắn.*(tăng giá|sinh lời)/i,
];

const item = $input.first().json;
if (!item.ok || !item.article) {
  return [{ json: { ...item, l0_pass: false, editorial_pass: false } }];
}

const text = [
  item.article.title,
  item.article.excerpt,
  item.article.body,
  item.article.seo_title,
  item.article.seo_desc,
].join('\n');

const editorialHits = [];
if (/\*\*/.test(text)) editorialHits.push('RAW_MARKDOWN_BOLD');
for (const phrase of BANNED_PHRASES) {
  if (text.toLowerCase().includes(String(phrase).toLowerCase())) {
    editorialHits.push(`BANNED:${phrase}`);
  }
}
if (/→\s*\[/.test(text)) editorialHits.push('ARROW_CTA');

const forbiddenHits = FORBIDDEN.filter((re) => re.test(text)).map((re) => re.source);

const pass = editorialHits.length === 0 && forbiddenHits.length === 0;

return [{
  json: {
    ...item,
    l0_pass: pass,
    editorial_pass: editorialHits.length === 0,
    editorial_hits: editorialHits,
    l0_hits: forbiddenHits,
    sheet_status: pass ? 'draft' : 'review',
    qa_tier: pass ? 'L0' : 'L0_FAIL',
  },
}];

const item = $input.first().json;
if (!item.ok || !item.article) {
  return [{ json: { ok: false, error: 'MERGE_SKIP', request_id: item.request_id } }];
}

const a = item.article;
const meta = {
  topic: item.topic,
  segment: item.segment,
  project_slug: item.project_slug,
  editorial_hits: item.editorial_hits || [],
  l0_hits: item.l0_hits || [],
  llm_provider: item.llm_provider,
  created_at: new Date().toISOString(),
  pipeline: 'housex-website-article-pr',
