    ok: true,
    request_id: item.request_id,
    sheet_status: item.sheet_status || 'draft',
    qa_tier: item.qa_tier || 'L0',
    append_row: [
      item.request_id,
      a.slug,
      a.title,
      a.excerpt,
      a.body,
      a.seo_title || '',
      a.seo_desc || '',
      JSON.stringify(a.tags),
      JSON.stringify(a.project_slugs),
      item.sheet_status || 'draft',
      item.qa_tier || 'L0',
      new Date().toISOString(),
      'n8n_housex_article',
      JSON.stringify(meta),
    ],
    article: a,
    meta,
  },
}];

const item = $input.first().json;
if (!item.ok || !item.append_row) {
  return [{ json: item }];
}

const sheetId = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const tab = 'housex_articles';

return [{
  json: {
    ...item,
    append_url: `https://sheets.googleapis.com/v4/spreadsheets/${sheetId}/values/${encodeURIComponent(`${tab}!A:N`)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`,
  },
}];

const item = $input.first().json;
const article = item.article || $('Merge Sheet Row').first()?.json?.article;

return [{
  json: {
    ok: item.ok !== false,
    workflow: 'content-housex-article',
    request_id: item.request_id,
    slug: article?.slug || null,
    title: article?.title || null,
    sheet_status: item.sheet_status || null,
    qa_tier: item.qa_tier || null,
    editorial_hits: item.editorial_hits || [],
    l0_hits: item.l0_hits || [],
